import{_ as r,c as a,o,ae as t}from"./chunks/framework.DN7zo1cr.js";const p="/images/DeepSeekProxy.png",s="/images/cross_s1.png",i="/images/cross_s2.png",y=JSON.parse('{"title":"DeepSeekProxy","description":"","frontmatter":{},"headers":[],"relativePath":"home/DeepSeek.md","filePath":"home/DeepSeek.md"}'),l={name:"home/DeepSeek.md"};function c(n,e,k,_,d,m){return o(),a("div",null,e[0]||(e[0]=[t('<h1 id="deepseekproxy" tabindex="-1">DeepSeekProxy <a class="header-anchor" href="#deepseekproxy" aria-label="Permalink to &quot;DeepSeekProxy&quot;">​</a></h1><blockquote><p>✨在1.61以上的版本中，插件支持调用DeepSeek的API进行答案解析<br> 🔓在不使用DeepSeekProxy的情况下，每个用户每日有50次的限额<br> 🖥️如果想要无限制地调用，需要使用DeepSeekProxy</p></blockquote><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>DeepSeekProxy是开源软件，不会上传用户的API Key</p></div><h2 id="_1️⃣获取api-key" tabindex="-1">1️⃣获取API Key <a class="header-anchor" href="#_1️⃣获取api-key" aria-label="Permalink to &quot;1️⃣获取API Key&quot;">​</a></h2><p><a href="./GetAPIKey">点击查看教程</a></p><h2 id="_2️⃣下载并运行deepseekproxy" tabindex="-1">2️⃣下载并运行DeepSeekProxy <a class="header-anchor" href="#_2️⃣下载并运行deepseekproxy" aria-label="Permalink to &quot;2️⃣下载并运行DeepSeekProxy&quot;">​</a></h2><ul><li><a href="https://wwyl.lanzouv.com/b00ocrzzje" target="_blank" rel="noreferrer">蓝奏云</a> 密码：43so</li><li><a href="https://gitee.com/m0zey/DeepSeekProxy/releases" target="_blank" rel="noreferrer">Gitee</a> 下载.7z文件</li></ul><p><img src="'+p+'" alt="images/DeepSeekProxy.png"> 填入相应平台的API Key点击保存即可</p><h2 id="_3️⃣为什么需要deepseekproxy" tabindex="-1">3️⃣为什么需要DeepSeekProxy？ <a class="header-anchor" href="#_3️⃣为什么需要deepseekproxy" aria-label="Permalink to &quot;3️⃣为什么需要DeepSeekProxy？&quot;">​</a></h2><p>因为目前所有的API都是不能跨域的，也就是说不能在一个网站中进行请求,所以需要搭建<code>代理服务器</code>。 <img src="'+s+'" alt="浏览器拦截"><img src="'+i+'" alt="浏览器拦截"></p><p>用户每日50次的非DeepSeekProxy调用使用的是我们服务器的资源，因此有限制。而使用DeepSeekProxy则相当于直接与大模型平台进行交互，完全不经过我们的服务器，不会对我们的服务器造成压力，所以没有限制。</p>',11)]))}const P=r(l,[["render",c]]);expor